// Java 25 exam prep - String pool vs object identity
// Learn: == compares references; equals compares value; literals share the pool.
String left = "exam";
String right = "ex" + "am";
// Constant expressions fold at compile time into the same pooled "exam".
String built = new StringBuilder("ex").append("am").toString();
System.out.println(left == right);
System.out.println(left == built);
// built is a fresh runtime object: identity differs while the value matches.
System.out.println(left.equals(built));
System.out.println(left == built.intern());
